package kr.gampa.battlegrounds.vehicle; public final class VehiclePhysics{private VehiclePhysics(){}public static VehicleState step(VehicleSpec s,VehicleState st,VehicleInput in,double dt){if(st.destroyed())return st;boolean powered=s.fuelCapacity()==0||st.fuel()>0;double boost=in.boost()&&powered?1.15:1;double limit=(in.throttle()<0?s.reverseSpeedKmh():s.topSpeedKmh())*boost;double speed=st.speedKmh();if(in.brake())speed*=Math.max(0,1-5*dt);else if(in.throttle()!=0&&powered){double target=Math.copySign(limit,in.throttle());double change=s.topSpeedKmh()*s.acceleration()*boost*dt;speed+=Math.copySign(Math.min(Math.abs(target-speed),change),target-speed);}else speed*=Math.max(0,1-.6*dt);double fuel=st.fuel();if(s.fuelCapacity()>0&&Math.abs(in.throttle())>0)fuel=Math.max(0,fuel-s.fuelPerSecond()*dt*(in.boost()?1.8:1));return new VehicleState(speed,fuel,st.durability(),false);}public static double terrainSpeed(VehicleSpec s,VehicleState st,boolean inWater){if(s.type()==VehicleType.AMPHIBIOUS)return st.speedKmh()*(inWater?.65:1);if(s.type()==VehicleType.WATER&&!inWater)return Math.copySign(Math.min(Math.abs(st.speedKmh()),20),st.speedKmh());if(s.type()==VehicleType.LAND&&inWater)return st.speedKmh()*.15;return st.speedKmh();}public static double collisionDamage(double impactKmh,double multiplier){if(impactKmh<20)return 0;double excess=impactKmh-20;return excess*excess*.12*Math.max(0,multiplier);}public static boolean canClimb(VehicleType type,double speed,double takeoff){return type==VehicleType.AIR&&speed>=takeoff;}}